import React, { useRef, useState } from 'react';
import { View, Alert, PermissionsAndroid, Platform, StyleSheet } from 'react-native';
import { WebView } from 'react-native-webview';
import Geolocation from '@react-native-community/geolocation';
import { launchCamera, launchImageLibrary } from 'react-native-image-picker';

const MobileWebView = ({ uri }) => {
  const webViewRef = useRef(null);
  const [allowedOrigins] = useState([
    'https://yourdomain.com',
    'https://www.yourdomain.com'
  ]);

  const isOriginAllowed = (origin) => {
    return allowedOrigins.some(allowed => origin.startsWith(allowed));
  };

  const requestLocationPermission = async () => {
    if (Platform.OS === 'android') {
      try {
        const granted = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.ACCESS_FINE_LOCATION,
          {
            title: 'Location Permission',
            message: 'This app needs access to your location',
            buttonNeutral: 'Ask Me Later',
            buttonNegative: 'Cancel',
            buttonPositive: 'OK',
          }
        );
        return granted === PermissionsAndroid.RESULTS.GRANTED;
      } catch (err) {
        console.warn(err);
        return false;
      }
    }
    return true;
  };

  const requestCameraPermission = async () => {
    if (Platform.OS === 'android') {
      try {
        const granted = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.CAMERA,
          {
            title: 'Camera Permission',
            message: 'This app needs access to your camera',
            buttonNeutral: 'Ask Me Later',
            buttonNegative: 'Cancel',
            buttonPositive: 'OK',
          }
        );
        return granted === PermissionsAndroid.RESULTS.GRANTED;
      } catch (err) {
        console.warn(err);
        return false;
      }
    }
    return true;
  };

  const getLocation = async () => {
    const hasPermission = await requestLocationPermission();
    
    if (!hasPermission) {
      return {
        success: false,
        error: 'Location permission denied'
      };
    }

    return new Promise((resolve) => {
      Geolocation.getCurrentPosition(
        (position) => {
          resolve({
            success: true,
            data: {
              latitude: position.coords.latitude,
              longitude: position.coords.longitude,
              accuracy: position.coords.accuracy,
              altitude: position.coords.altitude,
              heading: position.coords.heading,
              speed: position.coords.speed,
              timestamp: position.timestamp
            }
          });
        },
        (error) => {
          resolve({
            success: false,
            error: error.message
          });
        },
        {
          enableHighAccuracy: true,
          timeout: 15000,
          maximumAge: 10000
        }
      );
    });
  };

  const openCamera = async () => {
    const hasPermission = await requestCameraPermission();
    
    if (!hasPermission) {
      return {
        success: false,
        error: 'Camera permission denied'
      };
    }

    return new Promise((resolve) => {
      launchCamera(
        {
          mediaType: 'photo',
          quality: 0.8,
          maxWidth: 1920,
          maxHeight: 1920,
          includeBase64: true,
          saveToPhotos: false
        },
        (response) => {
          if (response.didCancel) {
            resolve({
              success: false,
              error: 'User cancelled camera'
            });
          } else if (response.errorCode) {
            resolve({
              success: false,
              error: response.errorMessage
            });
          } else if (response.assets && response.assets.length > 0) {
            resolve({
              success: true,
              data: {
                uri: response.assets[0].uri,
                base64: response.assets[0].base64,
                type: response.assets[0].type,
                fileName: response.assets[0].fileName,
                fileSize: response.assets[0].fileSize
              }
            });
          } else {
            resolve({
              success: false,
              error: 'No image captured'
            });
          }
        }
      );
    });
  };

  const openImagePicker = async () => {
    return new Promise((resolve) => {
      launchImageLibrary(
        {
          mediaType: 'photo',
          quality: 0.8,
          maxWidth: 1920,
          maxHeight: 1920,
          includeBase64: true,
          selectionLimit: 1
        },
        (response) => {
          if (response.didCancel) {
            resolve({
              success: false,
              error: 'User cancelled image picker'
            });
          } else if (response.errorCode) {
            resolve({
              success: false,
              error: response.errorMessage
            });
          } else if (response.assets && response.assets.length > 0) {
            resolve({
              success: true,
              data: {
                uri: response.assets[0].uri,
                base64: response.assets[0].base64,
                type: response.assets[0].type,
                fileName: response.assets[0].fileName,
                fileSize: response.assets[0].fileSize
              }
            });
          } else {
            resolve({
              success: false,
              error: 'No image selected'
            });
          }
        }
      );
    });
  };

  const handleMessage = async (event) => {
    try {
      const message = JSON.parse(event.nativeEvent.data);
      
      if (!message.id || !message.action) {
        console.warn('Invalid message format');
        return;
      }

      const origin = event.nativeEvent.url;
      const messageOrigin = new URL(origin).origin;
      
      if (!isOriginAllowed(messageOrigin)) {
        sendResponse(message.id, {
          success: false,
          error: 'Origin not allowed'
        });
        return;
      }

      let result;

      switch (message.action) {
        case 'getLocation':
          result = await getLocation();
          break;

        case 'openCamera':
          result = await openCamera();
          break;

        case 'openImagePicker':
          result = await openImagePicker();
          break;

        default:
          result = {
            success: false,
            error: 'Unknown action'
          };
      }

      sendResponse(message.id, result);
    } catch (error) {
      console.error('Error handling message:', error);
    }
  };

  const sendResponse = (messageId, response) => {
    const script = `
      (function() {
        try {
          if (window.ReactNativeWebViewCallbacks && window.ReactNativeWebViewCallbacks['${messageId}']) {
            window.ReactNativeWebViewCallbacks['${messageId}'](${JSON.stringify(response)});
            delete window.ReactNativeWebViewCallbacks['${messageId}'];
          }
        } catch (e) {
          console.error('Error in callback:', e);
        }
      })();
    `;
    
    if (webViewRef.current) {
      webViewRef.current.injectJavaScript(script);
    }
  };

  const injectedJavaScript = `
    (function() {
      window.ReactNativeWebViewCallbacks = {};
      
      window.callNativeFunction = function(action, params) {
        return new Promise((resolve, reject) => {
          const messageId = 'msg_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
          
          window.ReactNativeWebViewCallbacks[messageId] = function(response) {
            if (response.success) {
              resolve(response.data);
            } else {
              reject(new Error(response.error));
            }
          };
          
          setTimeout(() => {
            if (window.ReactNativeWebViewCallbacks[messageId]) {
              delete window.ReactNativeWebViewCallbacks[messageId];
              reject(new Error('Request timeout'));
            }
          }, 30000);
          
          window.ReactNativeWebView.postMessage(JSON.stringify({
            id: messageId,
            action: action,
            params: params
          }));
        });
      };
      
      window.getDeviceLocation = function() {
        return window.callNativeFunction('getLocation');
      };
      
      window.openDeviceCamera = function() {
        return window.callNativeFunction('openCamera');
      };
      
      window.openDeviceImagePicker = function() {
        return window.callNativeFunction('openImagePicker');
      };
      
      true;
    })();
  `;

  const onShouldStartLoadWithRequest = (request) => {
    const requestOrigin = new URL(request.url).origin;
    return isOriginAllowed(requestOrigin);
  };

  const onError = (syntheticEvent) => {
    const { nativeEvent } = syntheticEvent;
    console.error('WebView error:', nativeEvent);
    Alert.alert('Error', 'Failed to load the page');
  };

  return (
    <View style={styles.container}>
      <WebView
        ref={webViewRef}
        source={{ uri }}
        javaScriptEnabled={true}
        domStorageEnabled={true}
        onMessage={handleMessage}
        injectedJavaScript={injectedJavaScript}
        onShouldStartLoadWithRequest={onShouldStartLoadWithRequest}
        onError={onError}
        allowsInlineMediaPlayback={true}
        mediaPlaybackRequiresUserAction={false}
        mixedContentMode="never"
        allowsBackForwardNavigationGestures={true}
        startInLoadingState={true}
        scalesPageToFit={true}
        style={styles.webview}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  webview: {
    flex: 1,
  },
});

export default MobileWebView;